import{_ as i,o as e,c as a,a as n}from"./chunks/framework.8tiMeCK-.js";const p="/PenguinLab/assets/ch09_fig144.BMcDWh_k.webp",t="/PenguinLab/assets/ch09_fig145.-9lLrn5j.webp",l="/PenguinLab/assets/ch09_fig146.C99f7qvO.webp",c="/PenguinLab/assets/ch09_fig147.BA3Q6nq1.webp",d="/PenguinLab/assets/ch09_fig148.BzIpyvol.webp",m=JSON.parse('{"title":"9.6  实战：用原生 ftrace 追踪单次 Ping 请求","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch09_6.md","filePath":"notes/linux_kernel_debugging/ch09_6.md","lastUpdated":null}'),r={name:"notes/linux_kernel_debugging/ch09_6.md"};function o(h,s,k,g,_,u){return e(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="_9-6-实战-用原生-ftrace-追踪单次-ping-请求" tabindex="-1">9.6 实战：用原生 ftrace 追踪单次 Ping 请求 <a class="header-anchor" href="#_9-6-实战-用原生-ftrace-追踪单次-ping-请求" aria-label="Permalink to &quot;9.6  实战：用原生 ftrace 追踪单次 Ping 请求&quot;">​</a></h1><p>好了，工具箱已经打开了。我们现在有了配置内核的能力，有了简单的跟踪手段，也有了这一大堆高级的过滤技巧——Glob、索引、黑名单、命令。</p><p>再在纸上谈兵就没意思了。</p><p>现在，我们要把这些知识扔进真实战场。我们要向内核发射一个 Ping 包：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> packtpub.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后，利用我们刚才学的这些 ftrace 绝技，把这一瞬间内核里发生的所有故事——从 ICMP 包的构造，到网络协议栈的层层封装，再到驱动的发出——完整地复现出来。</p><hr><h3 id="策略-function-graph-与过滤的艺术" tabindex="-1">策略：function_graph 与过滤的艺术 <a class="header-anchor" href="#策略-function-graph-与过滤的艺术" aria-label="Permalink to &quot;策略：function_graph 与过滤的艺术&quot;">​</a></h3><p>在这个实战中，我们将全程使用 <code>function_graph</code> 跟踪器。</p><p>为什么？因为我们需要看到「流程」。之前的 <code>function</code> 跟踪器只给我们一个扁平的函数列表，就像看一堆散落的乐高积木；而 <code>function_graph</code> 会把积木拼成城堡，让我们看到谁调用了谁，层级多深。</p><p>但网络子系统太庞大了，如果不加过滤，日志会在几毫秒内爆炸。我们的脚本（<code>ch9/ftrace/ping_ftrace.sh</code>）提供了两种过滤思路：</p><ol><li><strong>通过 <code>available_filter_functions</code></strong>（这是我们在前面详细讲过的「索引过滤法」）</li><li><strong>通过 <code>set_event</code> 接口</strong></li></ol><p>这两种是互斥的。在脚本里，我们用一个变量 <code>FILTER_VIA_AVAIL_FUNCS</code> 来控制开关。默认设置为 <code>1</code>，也就是第一种方法。这是有原因的：第一种方法虽然配置起来稍微繁琐一点（你得处理索引），但它能提供最详尽的视图——它不仅仅是「选几个函数看」，而是「把整个网络子系统的调用链都拉出来，同时只保留相关的那部分」。</p><p>来看看脚本里的核心逻辑：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ch9/ftrace/ping_ftrace.sh</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">FILTER_VIA_AVAIL_FUNCS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;[+] Function filtering:&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ \${FILTER_VIA_AVAIL_FUNCS} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-eq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ] ; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">then</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 这种方法快，而且细节保留得完美！</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    filterfunc_idx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> read</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> write</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> packet_</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sock</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sk_</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> udp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    netdev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    netif_</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> napi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> icmp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;^ip_&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;xmit$&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev_</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qdisc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [...]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>这里调用的 <code>filterfunc_idx()</code> 就是我们在前一节实现的那个神器——基于索引的过滤。它把这些关键词（<code>sock</code>、<code>skb</code>、<code>icmp</code> 等）扔进 <code>available_filter_functions</code> 里去筛选行号，然后把行号反写回 <code>set_ftrace_filter</code>。</p><p>同时，我们也没忘记清理工作。脚本里还用了 <code>filterfunc_remove()</code>，确保某些我们不关心的噪音函数被剔除。</p><p>此外，脚本还特别关照了网卡驱动模块。在这个例子里，我们用的是 <code>e1000</code> 驱动：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KMOD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">e1000</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;[+] module filtering (for \${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KMOD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">})&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> lsmod</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${KMOD} ; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">then</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;[+] setting filter command: :mod:\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KMOD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&quot;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;:mod:\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KMOD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set_ftrace_filter</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这一步很关键。如果只跟踪协议栈不跟踪驱动，你就只能看到数据包递到了门口，却没看到它真正怎么发出去的。</p><hr><h3 id="先有鸡还是先有蛋-精确捕获的难题" tabindex="-1">先有鸡还是先有蛋：精确捕获的难题 <a class="header-anchor" href="#先有鸡还是先有蛋-精确捕获的难题" aria-label="Permalink to &quot;先有鸡还是先有蛋：精确捕获的难题&quot;">​</a></h3><p>到这里，一切看起来都很顺。但有一个棘手的问题藏在细节里。</p><p>我们只想追踪那个 <code>ping</code> 进程，而且只要它运行的 CPU 核上的活动。为了做到这一点，我们需要两件事：</p><ol><li>告诉 ftrace 只记录哪个 PID（通过 <code>set_event_pid</code>）。</li><li>告诉 ftrace 只监控哪个 CPU（通过 <code>tracing_cpumask</code>）。我们用 <code>taskset</code> 把 ping 绑在某个核上。</li></ol><p><strong>但问题来了</strong>：怎么拿到 PID？</p><p>你得先让进程跑起来，才能获取它的 PID。但如果你让进程跑起来，它可能在你配置好 ftrace 之前就已经把活干完了。这是个典型的竞态条件——先有鸡还是先有蛋？</p><p>如果直接在后台跑 <code>ping</code> 然后去抓 PID，当你把 PID 写入 <code>set_event_pid</code> 的时候，那个 ICMP 包可能早就发出去了，你的跟踪记录里只有空气。</p><p>为了解决这个问题，我们的脚本（<code>ping_ftrace.sh</code>）用了一个稍微复杂的「包装器」技巧。</p><p>我们写了一个辅助脚本叫 <code>runner</code>。主脚本和 <code>runner</code> 之间会进行一次同步握手，流程像这样：</p><ol><li>主脚本在后台启动 <code>runner</code>，并拿到它的 PID。</li><li><code>runner</code> 并不立刻执行 <code>ping</code>，而是<strong>在那儿等着</strong>。</li><li>主脚本拿着这个 PID，把它配置给 ftrace，把一切准备停当。</li><li>主脚本创建一个「触发文件」。</li><li><code>runner</code> 看到触发文件出现了，知道「舞台已搭好」，立刻执行 <code>exec ping ...</code>。</li></ol><p>这里有一个关键的技术细节：<code>runner</code> 使用了 <code>exec</code> 来启动 ping。在 Unix 里，<code>exec</code> 会用新进程替换当前进程的内存镜像，但<strong>保持 PID 不变</strong>。</p><p>这意味着，<code>runner</code> 的 PID 就是 <code>ping</code> 的 PID。我们在第 2 步配置 ftrace 时用的是 <code>runner</code> 的 PID，但实际上最终被跟踪的是 <code>ping</code>——因为它们是同一个 PID。</p><p>这不仅是个技巧，这是把同步问题变成一个确定性流程的工程解法。</p><p>等到 <code>ping</code> 跑完，主脚本就会把报告保存下来。</p><p>如果你觉得这个流程「太折腾了」——没错，确实很折腾。为了追踪一个简单的命令，我们写了这么多同步逻辑。这正是为什么下一章我们要介绍 <code>trace-cmd</code> 的原因：它会把这些脏活累活全包了。</p><hr><h3 id="上号-看结果" tabindex="-1">上号！看结果 <a class="header-anchor" href="#上号-看结果" aria-label="Permalink to &quot;上号！看结果&quot;">​</a></h3><p>让我们跑一下脚本。</p><p>图 9.11 展示了脚本运行的瞬间。你可以看到脚本在输出各种日志，ping 在工作，最后提示报告已生成。</p><p><img src="`+p+'" alt="figure"></p><p><em>图 9.11 – 我们的 raw ftrace 脚本正在追踪单次 ping</em></p><p>注意看生成报告的大小——只有 272 KB。</p><p>如果你不加过滤，一次 ping 产生的 trace 可能有好几十 MB。这说明我们的过滤策略生效了：我们砍掉了无关的噪音，只留下了网络栈的精华。</p><p>你可以在源码的 <code>ch9/ftrace/ping_ftrace_report.txt</code> 找到这份报告。当然，你的环境跑出来的结果可能会略有不同，这取决于内核版本和硬件。</p><p>这个报告虽然精简了，但依然很长。我们在里面应该看什么？这里有几个关键的「地标」：</p><ol><li><code>__sys_socket()</code>：Ping 程序创建套接字的地方。</li><li><strong>发送路径</strong>：通常叫 tx。找 <code>sock_sendmsg()</code>，这是发包的起点。</li><li><strong>接收路径</strong>：通常叫 rx。找 <code>net_rx_action()</code>。</li></ol><hr><h3 id="深入发送路径" tabindex="-1">深入发送路径 <a class="header-anchor" href="#深入发送路径" aria-label="Permalink to &quot;深入发送路径&quot;">​</a></h3><p>让我们放大发送路径。当 ping 决定发一个包时，内核会走过这一串函数（自上而下）：</p><ul><li><code>sock_sendmsg()</code></li><li><code>inet_sendmsg()</code></li><li><code>udp_sendmsg()</code> (Ping 用的是 UDP 协议吗？不，Ping 是 ICMP，但在 Linux 内核里，某些路径可能会复用 UDP 的发送逻辑或类似的封装，或者这里是原文泛指网络发送。<em>注：严格来说 Ping 用 RAW socket 发 ICMP，但这里按原文逻辑描述</em> -&gt; 原文提到 <code>udp_sendmsg</code> 等函数，这是典型的网络栈发送流经之路)</li><li><code>ip_send_skb()</code></li><li><code>ip_output()</code></li><li><code>dev_queue_xmit()</code></li><li><code>dev_hard_start_xmit()</code></li></ul><p>最后这个函数就是通往驱动程序的门槛。在这个例子里，它会调用 <code>e1000_xmit_frame()</code>，把数据包真正丢给网卡硬件。</p><p>看看图 9.12，这是真实 trace 报告的截图。你能清晰地看到 <code>sock_sendmsg</code> 和 <code>inet_sendmsg</code> 被高亮出来了。</p><p><img src="'+t+'" alt="figure"></p><p><em>图 9.12 – 发送路径的 trace 片段（上半部分）</em></p><p>再往下走一点，图 9.13 显示了更深层次的调用。</p><p><img src="'+l+'" alt="figure"></p><p><em>图 9.13 – 发送路径的 trace 片段（下半部分，深入 UDP/IP 层和驱动层）</em></p><p>看到那些缩进了吗？</p><p>那不是排版，那是<strong>时间的流逝</strong>。每一个缩进层级，都是一次函数调用；每一次缩进回退，都是一次返回。</p><p>这就是 <code>function_graph</code> 的魅力。它不仅仅是日志，它是一段可以回放的电影。</p><hr><h3 id="深入接收路径" tabindex="-1">深入接收路径 <a class="header-anchor" href="#深入接收路径" aria-label="Permalink to &quot;深入接收路径&quot;">​</a></h3><p>包发出去后，还得收回来。</p><p>接收路径通常由中断触发，然后软中断 <code>NET_RX_SOFTIRQ</code> 接管。你在 trace 里应该能找到这些标志性函数：</p><ul><li><code>net_rx_action()</code>：这是软中断的主处理循环。</li><li><code>__netif_receive_skb()</code>：把数据包往协议栈上层递。</li><li><code>ip_rcv()</code>：IP 层处理。</li><li><code>udp_rcv()</code> 或 <code>icmp_rcv()</code>：协议层分发。</li><li><code>sock_recvmsg()</code>：最终数据到达用户空间。</li></ul><p>看图 9.14，这里是接收路径的开端。</p><p><img src="'+c+'" alt="figure"></p><p><em>图 9.14 – 接收路径的 trace 片段</em></p><p>而图 9.15 展示了数据包最终如何被递交给 Socket 层。</p><p><img src="'+d+'" alt="figure"></p><p><em>图 9.15 – 接收路径的最后阶段</em></p><h3 id="验证我们的直觉" tabindex="-1">验证我们的直觉 <a class="header-anchor" href="#验证我们的直觉" aria-label="Permalink to &quot;验证我们的直觉&quot;">​</a></h3><p>说实话，我第一次看到这个输出时，感觉非常奇妙。</p><p>平时我们写代码，<code>socket()</code> -&gt; <code>send()</code> -&gt; <code>recv()</code>，感觉像是在调用黑盒 API。但现在，通过 ftrace，这个黑盒被强行打开了。</p><p>你可以看到 <code>inet_sendmsg</code> 是怎么把通用请求转成 UDP/IP 请求的；你可以看到 <code>dev_queue_xmit</code> 是怎么排队等待网卡空闲的；你可以看到，当硬件中断发生时，内核是如何暂停当前进程，跳转到 <code>net_rx_action</code> 去处理包的。</p><p>这一节表面上是在讲 Ping，实际上我们是在验证内核网络栈的设计直觉。如果你发现代码的执行路径和你脑子里想的不一样，那就说明你的模型需要修正——而 ftrace 就是那个修正模型的工具。</p><p>现在，我们用最原始的工具（shell 脚本 + tracefs）完成了这个任务。你一定感觉到了：<strong>虽然可行，但很繁琐</strong>。</p><p>下一节，我们将引入 <code>trace-cmd</code>。看看它是如何把这套复杂的「同步、过滤、抓取、格式化」流程，浓缩成一行命令的。</p>',79)])])}const b=i(r,[["render",o]]);export{m as __pageData,b as default};
